    if requirements_file and os.path.exists(requirements_file):
        print(f"[setup.py] Installing from requirements file: {requirements_file}")
        try:
            subprocess.check_call(
                [sys.executable, "-m", "pip", "install", "-r", requirements_file],
                stdout=sys.stdout,
                stderr=sys.stderr,
            )
        except subprocess.CalledProcessError as e:
            print(f"[setup.py] Warning: pip install from requirements failed: {e}")
        finally:
            # Clean up temporary file
            if requirements_file == "._remote_requirements.txt":
                try:
                    os.remove(requirements_file)
                except OSError:
                    pass


